import redis
from rediscluster import RedisCluster

# Establish connection to the cluster
startup_nodes = [{"host": "127.0.0.1", "port": "7000"}, {"host": "127.0.0.1", "port": "7001"}]
rc = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)


def cache_user_data(user_id, session_token, api_key, ttl):
    # Store data with the user_id as the key
    # Set appropriate Time-To-Live (TTL) for security
    user_data = {"session_token": session_token, "api_key": api_key}
    rc.hmset(user_id, user_data)
    rc.expire(user_id, ttl)


def get_user_data(user_id):
    # Retrieve data from Redis
    return rc.hgetall(user_id)